                'wo': wo.group(1),
                'machine': machine.group(1),
                'tech': tech.group(1),
                'time': parse_time(day_match.group(1), comp.group(1))
            })

# Sort reports by machine and time
m_reports = defaultdict(list)
for r in sorted(reports, key=lambda x: x['time']):
