    reader = csv.DictReader(f)
    for row in reader:
        batch_id = row['batch_id']
        job_id = row['job_id']
        if job_id in jobs:
            batches[batch_id] = {
                'job_id': job_id,
                'machine': jobs[job_id]['machine'],
                'start_time': jobs[job_id]['start_time'],
                'product': row['product_id']
            }

# Load inspections
inspections = {}
with open('/app/quality_inspections.csv', 'r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        inspections[row['batch_id']] = row['inspection_result'] # ACCEPTED or REJECTED

# Map batches to maintenance windows
windows = []
for m, reps in m_reports.items():
    for i in range(len(reps)):
        start = reps[i]['time']
        end = reps[i+1]['time'] if i + 1 < len(reps) else float('inf')
        windows.append({
